           <div className="absolute top-4 left-4 flex items-center gap-1 bg-gray-50 px-3 py-1.5 rounded-full border border-gray-100 shadow-sm">
              {isOnline ? <Wifi size={16} className="text-green-600" /> : <WifiOff size={16} className="text-red-500" />}
              <span className={`text-xs font-bold ${isOnline ? 'text-green-700' : 'text-red-600'}`}>{isOnline ? 'متصل' : 'غير متصل'}</span>
           </div>
           <div className="text-center mb-8 mt-4">
             <div className="w-16 h-16 bg-blue-600 rounded-full flex items-center justify-center mx-auto mb-4 shadow-blue-200 shadow-lg"><Lock className="text-white" size={32} /></div>
             <h1 className="text-xl font-bold text-gray-800">نظام إحالة المتدربين</h1>
             <p className="text-gray-500 mt-2 text-sm">الكلية التقنية بالطائف - قسم التقنية الميكانيكية</p>
           </div>
           {isLoading ? (
             <div className="flex flex-col items-center justify-center py-10 gap-2"><Loader2 className="animate-spin text-blue-600" size={32} /><p className="text-xs text-gray-400">جاري الاتصال بقاعدة البيانات...</p></div>
           ) : (
             <form onSubmit={handleLogin} className="space-y-6">
               <div>
                 <label className="block text-sm font-bold text-gray-700 mb-2">اسم المستخدم</label>
                 <div className="relative">
                   <select value={loginUser} onChange={(e) => setLoginUser(e.target.value)} className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none appearance-none bg-white transition-shadow">
                     <option value="">اختر الاسم من القائمة...</option>
                     {staff.map(s => <option key={s.id} value={s.username}>{s.name} ({s.role === UserRole.HOD ? 'رئيس قسم' : (s.isCounselor ? 'مرشد تدريبي' : 'مدرب')})</option>)}
                   </select>
                   <ChevronDown className="absolute left-3 top-3.5 text-gray-400 pointer-events-none" size={20} />
                 </div>
               </div>
               <div>
                 <label className="block text-sm font-bold text-gray-700 mb-2">كلمة المرور</label>
                 <input type="password" value={loginPass} onChange={(e) => setLoginPass(e.target.value)} className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-shadow" placeholder="****" />
               </div>
               {loginError && <div className="p-3 bg-red-50 text-red-600 text-sm rounded-lg text-center font-medium">{loginError}</div>}
               <button type="submit" className="w-full bg-blue-600 text-white py-3 rounded-lg font-bold hover:bg-blue-700 transition shadow-lg hover:shadow-xl transform hover:-translate-y-0.5 duration-200">دخول</button>
             </form>
           )}
           <div className="mt-8 text-center border-t border-dashed pt-4">
             <p className="text-[10px] text-gray-400 mb-1">الإصدار 1.2.2 - السيرفر: Firebase</p>
             <p className="text-xs text-blue-500 font-semibold cursor-default">تطوير م. عبدالله الزهراني</p>
           </div>
        </div>
      </div>
    );
  }

  const effectiveRole = currentUser?.isCounselor ? UserRole.COUNSELOR : (currentUser?.role || UserRole.TRAINER);

  const renderContent = () => {
    if (!currentUser) return null;
    switch (activePage) {
      case 'dashboard': return <Dashboard referrals={referrals} />;
      case 'new-referral':
        return (
          <NewReferral trainees={trainees} staff={staff} currentUser={currentUser} onSubmit={handleUpdateReferral}
            onCancel={() => { setEditingReferral(undefined); setActivePage(effectiveRole === UserRole.TRAINER ? 'referrals' : 'dashboard'); }}
            initialData={editingReferral} />
        );
      case 'referrals':
        return <ReferralsList referrals={referrals} onEdit={handleEditReferral} currentUser={currentUser} onDelete={handleDeleteReferral} />;
      case 'staff':
        if (currentUser.role !== UserRole.HOD) return <div className="p-8 text-center text-red-500">غير مصرح لك بالوصول</div>;
        return <StaffManagement staff={staff} setStaff={(newDetails) => { /* logic in original file */ }} currentUserSpecialization={currentUser.specialization} />;
      case 'profile': return <Profile currentUser={currentUser} updateUserPassword={handleUpdatePassword} />;
      default: return <Dashboard referrals={referrals} />;
    }
  };

  return (
    <div className="flex min-h-screen bg-gray-50 font-cairo">
      <Sidebar activePage={activePage} setActivePage={(page) => { if(page === 'new-referral') setEditingReferral(undefined); setActivePage(page); }} 
        currentUserRole={effectiveRole} onLogout={handleLogout} notificationCount={notificationCount} />
      <main className="flex-1 p-4 md:p-8 overflow-y-auto pb-24 md:pb-8 flex flex-col w-full max-w-full">
        <header className="mb-6 md:mb-8 flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex items-center justify-between md:block">
            <div>
              <h1 className="text-xl md:text-2xl font-bold text-gray-800">
                {activePage === 'dashboard' && 'لوحة المعلومات'}
                {activePage === 'new-referral' && (editingReferral ? 'متابعة الحالة / التعديل' : 'إحالة جديدة')}
                {activePage === 'referrals' && 'سجل الإحالات والمتابعة'}
                {activePage === 'staff' && 'إدارة المدربين'}
                {activePage === 'profile' && 'إعدادات الحساب'}
              </h1>
              <p className="text-gray-500 text-xs md:text-sm mt-1">الكلية التقنية بالطائف - قسم التقنية الميكانيكية</p>
            </div>
            <div className="md:hidden flex items-center bg-white px-2 py-1 rounded-full shadow-sm border border-gray-100">
               {isOnline ? <Wifi size={16} className="text-green-600" /> : <WifiOff size={16} className="text-red-500 animate-pulse" />}
            </div>
          </div>
          <div className="flex items-center gap-2 md:gap-4 self-end md:self-auto">
            <div className="hidden md:flex items-center gap-2 bg-white px-3 py-2 rounded-xl shadow-sm border border-gray-100">
               {isOnline ? <Wifi size={18} className="text-green-500"/> : <WifiOff size={18} className="text-red-500"/>}
               <span className={`text-xs font-bold ${isOnline ? 'text-green-700' : 'text-red-600'}`}>{isOnline ? 'متصل بالسيرفر' : 'غير متصل'}</span>
            </div>
            <div className="relative z-10">
              <button onClick={() => setShowNotifications(!showNotifications)} className="relative p-2 bg-white rounded-xl shadow-sm border border-gray-100 text-gray-600 hover:text-blue-600 transition">
                <Bell size={24} />
                {notificationCount > 0 && <span className="absolute -top-1 -right-1 bg-red-500 text-white text-xs font-bold w-5 h-5 flex items-center justify-center rounded-full animate-pulse border-2 border-white">{notificationCount}</span>}
              </button>
              {showNotifications && (
                <div className="absolute left-0 rtl:left-auto rtl:right-0 md:rtl:left-0 mt-2 w-72 md:w-80 bg-white rounded-xl shadow-lg border border-gray-100 overflow-hidden z-20">
                  <div className="p-3 border-b border-gray-100 font-bold text-gray-700 bg-gray-50 flex justify-between items-center">
                    <span>الإشعارات</span><span className="bg-red-100 text-red-600 text-xs px-2 py-0.5 rounded-full">{notificationCount}</span>
                  </div>
                  <div className="max-h-64 overflow-y-auto">
                    {pendingReferrals.length > 0 ? (
                      pendingReferrals.map((referral) => (
                        <div key={referral.id} onClick={() => handleEditReferral(referral)} className="p-3 border-b border-gray-50 hover:bg-blue-50 cursor-pointer transition flex flex-col gap-1">
                          <div className="flex justify-between items-start"><span className="font-bold text-sm text-gray-800">{referral.traineeName}</span><span className="text-[10px] text-gray-400">{new Date(referral.date).toLocaleDateString('ar-SA')}</span></div>
                          <div className="flex justify-between items-center"><p className="text-xs text-blue-600 font-medium truncate">{referral.status}</p>{referral.repetition === 'دائم التكرار' && <span className="text-[10px] bg-red-100 text-red-600 px-1 rounded">متكرر</span>}</div>
                        </div>
                      ))
                    ) : <div className="p-6 text-center text-gray-400 text-sm">لا توجد إشعارات جديدة</div>}
                  </div>
                </div>
              )}
            </div>
            <div className="flex items-center gap-2 bg-white p-2 rounded-xl shadow-sm border border-gray-100 px-3 cursor-pointer hover:bg-gray-50 transition" onClick={() => setActivePage('profile')}>
              <UserCircle2 className="text-blue-600" />
              <div className="text-sm hidden md:block">
                <p className="font-bold text-gray-800">{currentUser?.name}</p>
                <p className="text-xs text-gray-500">{currentUser?.role === UserRole.HOD ? `رئيس قسم - ${currentUser.specialization}` : currentUser?.role}{currentUser?.isCounselor && ' (مشرف إرشاد)'}</p>
              </div>
            </div>
          </div>
        </header>
        {renderContent()}
      </main>
      <MobileNav activePage={activePage} setActivePage={(page) => { if(page === 'new-referral') setEditingReferral(undefined); setActivePage(page); }} currentUserRole={effectiveRole} notificationCount={notificationCount} onLogout={handleLogout} />
    </div>
  );
};

export default App;

